const VALID_METRICS = [
	"session_count",
	"avg_duration",
	"total_duration",
	"avg_interactions",
	"total_interactions",
	"avg_response_time",
	"median_response_time",
	"avg_tokens",
	"total_tokens",
	"avg_success_score",
	"avg_errors",
	"total_errors",
] as const;

