// ── Errors ─────────────────────────────────────────────────────────

export const RecurringErrorSchema = z.object({
	error_pattern: z.string(),
	occurrences: z.number(),
	affected_sessions: z.number(),
	affected_users: z.number(),
	last_seen: z.string(),
	severity: z.enum(["high", "medium", "low"]),
	repositories: z.array(z.string()),
