  1→import * as p from "@clack/prompts";
  2→import { buildCommand } from "@stricli/core";
  3→import { type BatchOptions, batchUpload } from "../lib/batch-uploader.js";
  4→import { classifySession } from "../lib/classifier.js";
  5→import { loadCredentials } from "../lib/credentials.js";
  6→import { getGitInfo } from "../lib/git-info.js";
  7→import { getProjectOrgId } from "../lib/project-config.js";
  8→import {
  9→	groupProjectsForCwd,
 10→	type ScannedProject,
 11→	scanProjects,
 12→} from "../lib/project-scanner.js";
 13→import { resolveSession } from "../lib/session-resolver.js";
 14→import { readSubagentFiles } from "../lib/subagent-reader.js";
 15→import { extractAgentIds, readTranscript } from "../lib/transcript-reader.js";
 16→import {
 17→	DEFAULT_ENDPOINT,
 18→	type IngestRequest,
 19→	SESSION_TAGS,
 20→	type SessionTag,
 21→	type SubagentFile,
 22→} from "../lib/types.js";
 23→import { uploadSession } from "../lib/uploader.js";
 24→
 25→interface UploadFlags {
 26→	tag?: SessionTag;
 27→	endpoint: string;
 28→	classify: boolean;
 29→	dryRun: boolean;
 30→	org?: string;
 31→}
 32→
 33→async function runInteractiveUpload(flags: UploadFlags): Promise<void> {
 34→	const credentials = loadCredentials();
 35→	if (!credentials && !flags.dryRun) {
 36→		p.log.error("Not authenticated. Run `rudel login` first.");
 37→		process.exitCode = 1;
 38→		return;
 39→	}
 40→
 41→	p.intro("rudel upload");
 42→
 43→	const spin = p.spinner();
 44→	spin.start("Scanning projects...");
 45→	const projects = await scanProjects();
 46→	spin.stop(`Found ${projects.length} project(s)`);
 47→
 48→	if (projects.length === 0) {
 49→		p.log.warn("No projects with sessions found in ~/.claude/projects/");
 50→		p.outro("Nothing to upload.");
 51→		return;
 52→	}
 53→
 54→	const cwd = process.cwd();
 55→	const grouped = groupProjectsForCwd(projects, cwd);
 56→
 57→	const options: Array<{
 58→		value: ScannedProject;
 59→		label: string;
 60→		hint: string;
 61→	}> = [];
 62→	const preSelected: ScannedProject[] = [];
 63→
 64→	if (grouped.current) {
 65→		options.push({
 66→			value: grouped.current,
 67→			label: grouped.current.displayPath,
 68→			hint: sessionCountHint(grouped.current.sessionCount),
 69→		});
 70→		preSelected.push(grouped.current);
 71→
 72→		for (const sub of grouped.subfolders) {
 73→			const relative = sub.decodedPath.slice(
 74→				grouped.current.decodedPath.length + 1,
 75→			);
 76→			options.push({
 77→				value: sub,
 78→				label: `  ${relative}`,
 79→				hint: sessionCountHint(sub.sessionCount),
 80→			});
 81→			preSelected.push(sub);
 82→		}
 83→	}
 84→
 85→	for (const other of grouped.others) {
 86→		options.push({
 87→			value: other,
 88→			label: other.displayPath,
 89→			hint: sessionCountHint(other.sessionCount),
 90→		});
 91→	}
 92→
 93→	const selected = await p.multiselect({
 94→		message: "Select projects to upload",
 95→		options,
 96→		initialValues: preSelected,
 97→		required: true,
 98→	});
 99→
100→	if (p.isCancel(selected)) {
101→		p.cancel("Upload cancelled.");
102→		return;
103→	}
104→
105→	const totalSessions = selected.reduce(
106→		(sum, proj) => sum + proj.sessionCount,
107→		0,
108→	);
109→	p.log.info(
110→		`Uploading ${totalSessions} session(s) from ${selected.length} project(s)`,
111→	);
112→
113→	const batchOpts: BatchOptions = {
114→		tag: flags.tag,
115→		classify: flags.classify,
116→		dryRun: flags.dryRun,
117→		org: flags.org,
118→		uploadConfig: {
119→			endpoint: flags.endpoint,
120→			token: credentials?.token ?? "",
121→		},
122→	};
123→
124→	const uploadSpin = p.spinner();
125→	uploadSpin.start("Uploading sessions...");
126→
127→	const result = await batchUpload(selected, batchOpts, (current, total) => {
128→		uploadSpin.message(`[${current}/${total}] Uploading...`);
129→	});
130→
131→	uploadSpin.stop("Upload complete");
132→
133→	if (result.succeeded > 0) {
134→		p.log.success(`${result.succeeded} session(s) uploaded successfully`);
135→	}
136→	if (result.failed > 0) {
137→		p.log.error(`${result.failed} session(s) failed`);
138→		for (const err of result.errors.slice(0, 5)) {
139→			p.log.warn(`  ${err.project}/${err.sessionId}: ${err.error}`);
140→		}
141→		if (result.errors.length > 5) {
142→			p.log.warn(`  ...and ${result.errors.length - 5} more`);
143→		}
144→	}
145→
146→	if (flags.dryRun) {
147→		p.outro("Dry run complete — no sessions were uploaded.");
148→	} else {
149→		p.outro("Done!");
150→	}
151→
152→	if (result.failed > 0) {
153→		process.exitCode = 1;
154→	}
155→}
156→
157→function sessionCountHint(count: number): string {
158→	return `${count} session${count !== 1 ? "s" : ""}`;
159→}
160→
161→async function runSingleUpload(
162→	flags: UploadFlags,
163→	session: string,
164→): Promise<void> {
165→	const write = (msg: string) => {
166→		process.stdout.write(`${msg}\n`);
167→	};
168→	const writeError = (msg: string) => {
169→		process.stderr.write(`${msg}\n`);
170→	};
171→
172→	const credentials = loadCredentials();
173→	if (!credentials && !flags.dryRun) {
174→		writeError("Error: Not authenticated. Run `rudel login` first.");
175→		process.exitCode = 1;
176→		return;
177→	}
178→
179→	write(`Resolving session: ${session}`);
180→	let sessionInfo: Awaited<ReturnType<typeof resolveSession>>;
181→	try {
182→		sessionInfo = await resolveSession(session);
183→	} catch (error) {
184→		writeError(
185→			`Error: ${error instanceof Error ? error.message : String(error)}`,
186→		);
187→		process.exitCode = 1;
188→		return;
189→	}
190→	write(`Found session at: ${sessionInfo.transcriptPath}`);
191→
192→	write("Reading transcript...");
193→	let content: string;
194→	try {
195→		content = await readTranscript(sessionInfo.transcriptPath);
196→	} catch (error) {
197→		writeError(
198→			`Error reading transcript: ${error instanceof Error ? error.message : String(error)}`,
199→		);
200→		process.exitCode = 1;
201→		return;
202→	}
203→	write(`Transcript: ${content.length} bytes`);
204→
205→	const agentIds = extractAgentIds(content);
206→	let subagents: SubagentFile[] = [];
207→	if (agentIds.length > 0) {
208→		write(`Found ${agentIds.length} subagent(s): ${agentIds.join(", ")}`);
209→		subagents = await readSubagentFiles(
210→			sessionInfo.sessionDir,
211→			agentIds,
212→			sessionInfo.sessionId,
213→		);
214→		write(
215→			`Read ${subagents.length} subagent file(s): ${subagents.reduce((sum, s) => sum + s.content.length, 0)} bytes total`,
216→		);
217→	}
218→
219→	const gitInfo = await getGitInfo(sessionInfo.projectPath);
220→	if (gitInfo.repository) write(`Repository: ${gitInfo.repository}`);
221→	if (gitInfo.branch) write(`Branch: ${gitInfo.branch}`);
222→
223→	let tag = flags.tag;
224→	if (!tag && flags.classify) {
225→		write("Classifying session...");
226→		tag = (await classifySession(content)) ?? undefined;
227→		if (tag) write(`Classified as: ${tag}`);
228→	}
229→
230→	const organizationId =
231→		flags.org ?? (await getProjectOrgId(sessionInfo.projectPath));
232→	if (organizationId) write(`Organization: ${organizationId}`);
233→
234→	const request: IngestRequest = {
235→		sessionId: sessionInfo.sessionId,
236→		projectPath: sessionInfo.projectPath,
