import * as p from "@clack/prompts";
import { buildCommand } from "@stricli/core";
import { type BatchOptions, batchUpload } from "../lib/batch-uploader.js";
import { classifySession } from "../lib/classifier.js";
import {
	type ScannedCodexProject,
	scanCodexSessions,
} from "../lib/codex-scanner.js";
import { uploadOneCodexSession } from "../lib/codex-uploader.js";
import { loadCredentials } from "../lib/credentials.js";
import { getGitInfo } from "../lib/git-info.js";
import { getProjectOrgId } from "../lib/project-config.js";
import {
	groupProjectsForCwd,
	type ScannedProject,
	scanProjects,
} from "../lib/project-scanner.js";
import { resolveSession } from "../lib/session-resolver.js";
import { readSubagentFiles } from "../lib/subagent-reader.js";
import { extractAgentIds, readTranscript } from "../lib/transcript-reader.js";
import {
	DEFAULT_ENDPOINT,
	type IngestRequest,
	SESSION_TAGS,
	type SessionTag,
	type SubagentFile,
} from "../lib/types.js";
import { type UploadConfig, uploadSession } from "../lib/uploader.js";

interface UploadFlags {
	tag?: SessionTag;
	endpoint: string;
	classify: boolean;
	dryRun: boolean;
	org?: string;
}

async function runInteractiveUpload(flags: UploadFlags): Promise<void> {
	const credentials = loadCredentials();
	if (!credentials && !flags.dryRun) {
		p.log.error("Not authenticated. Run `rudel login` first.");
		process.exitCode = 1;
		return;
	}

	p.intro("rudel upload");

	const spin = p.spinner();
	spin.start("Scanning projects...");
	const [claudeProjects, codexProjects] = await Promise.all([
		scanProjects(),
		scanCodexSessions(),
	]);
	const totalProjectCount = claudeProjects.length + codexProjects.length;
	spin.stop(`Found ${totalProjectCount} project(s)`);

	if (totalProjectCount === 0) {
		p.log.warn("No projects with sessions found.");
		p.outro("Nothing to upload.");
		return;
	}

	type SelectionItem =
		| { source: "claude"; project: ScannedProject }
		| { source: "codex"; project: ScannedCodexProject };

	const cwd = process.cwd();
	const grouped = groupProjectsForCwd(claudeProjects, cwd);

	const options: Array<{
		value: SelectionItem;
		label: string;
		hint: string;
	}> = [];
	const preSelected: SelectionItem[] = [];

	if (grouped.current) {
		const item: SelectionItem = {
			source: "claude",
			project: grouped.current,
		};
		options.push({
			value: item,
			label: `[Claude] ${grouped.current.displayPath}`,
			hint: sessionCountHint(grouped.current.sessionCount),
		});
		preSelected.push(item);

		for (const sub of grouped.subfolders) {
			const relative = sub.decodedPath.slice(
				grouped.current.decodedPath.length + 1,
			);
			const subItem: SelectionItem = { source: "claude", project: sub };
			options.push({
				value: subItem,
				label: `  [Claude] ${relative}`,
				hint: sessionCountHint(sub.sessionCount),
			});
			preSelected.push(subItem);
		}
	}

	for (const other of grouped.others) {
		options.push({
			value: { source: "claude", project: other },
			label: `[Claude] ${other.displayPath}`,
			hint: sessionCountHint(other.sessionCount),
		});
	}

	for (const codexProject of codexProjects) {
		const item: SelectionItem = { source: "codex", project: codexProject };
		const isCurrent = codexProject.projectPath === cwd;
		options.push({
			value: item,
			label: `[Codex] ${codexProject.displayPath}`,
			hint: sessionCountHint(codexProject.sessionCount),
		});
		if (isCurrent) {
			preSelected.push(item);
		}
	}

	const selected = await p.multiselect({
		message: "Select projects to upload",
		options,
		initialValues: preSelected,
		required: true,
	});

	if (p.isCancel(selected)) {
		p.cancel("Upload cancelled.");
		return;
	}

	const claudeSelected = selected
		.filter(
			(s): s is SelectionItem & { source: "claude" } => s.source === "claude",
		)
		.map((s) => s.project);
	const codexSelected = selected
		.filter(
			(s): s is SelectionItem & { source: "codex" } => s.source === "codex",
		)
		.map((s) => s.project);

	const totalSessions =
		claudeSelected.reduce((sum, proj) => sum + proj.sessionCount, 0) +
		codexSelected.reduce((sum, proj) => sum + proj.sessionCount, 0);
	p.log.info(
		`Uploading ${totalSessions} session(s) from ${selected.length} project(s)`,
	);

	const uploadConfig: UploadConfig = {
		endpoint: flags.endpoint,
		token: credentials?.token ?? "",
	};

	const uploadSpin = p.spinner();
	uploadSpin.start("Uploading sessions...");

	let succeeded = 0;
	let failed = 0;
	const errors: Array<{ sessionId: string; project: string; error: string }> =
		[];
	let completed = 0;

	// Upload Claude sessions
	if (claudeSelected.length > 0) {
		const batchOpts: BatchOptions = {
			tag: flags.tag,
			classify: flags.classify,
			dryRun: flags.dryRun,
			org: flags.org,
			uploadConfig,
		};

		const claudeResult = await batchUpload(
			claudeSelected,
			batchOpts,
			(current, total) => {
				uploadSpin.message(
					`[${completed + current}/${totalSessions}] Uploading...`,
				);
			},
		);
		succeeded += claudeResult.succeeded;
		failed += claudeResult.failed;
		errors.push(...claudeResult.errors);
		completed += claudeSelected.reduce(
			(sum, proj) => sum + proj.sessionCount,
			0,
		);
	}

	// Upload Codex sessions
	for (const codexProject of codexSelected) {
		for (const session of codexProject.sessions) {
			completed++;
			uploadSpin.message(`[${completed}/${totalSessions}] Uploading...`);

			const outcome = await uploadOneCodexSession(
				session,
				codexProject.projectPath,
				{
					tag: flags.tag,
					dryRun: flags.dryRun,
					org: flags.org,
					uploadConfig,
				},
			);

			if (outcome.success) {
				succeeded++;
			} else {
				failed++;
				errors.push({
					sessionId: session.meta.id,
					project: codexProject.displayPath,
					error: outcome.error ?? "Unknown error",
				});
			}
		}
	}

	uploadSpin.stop("Upload complete");

	if (succeeded > 0) {
		p.log.success(`${succeeded} session(s) uploaded successfully`);
	}
	if (failed > 0) {
		p.log.error(`${failed} session(s) failed`);
		for (const err of errors.slice(0, 5)) {
			p.log.warn(`  ${err.project}/${err.sessionId}: ${err.error}`);
		}
		if (errors.length > 5) {
			p.log.warn(`  ...and ${errors.length - 5} more`);
		}
	}

	if (flags.dryRun) {
		p.outro("Dry run complete — no sessions were uploaded.");
	} else {
		p.outro("Done!");
	}

	if (failed > 0) {
		process.exitCode = 1;
	}
}

function sessionCountHint(count: number): string {
	return `${count} session${count !== 1 ? "s" : ""}`;
}

async function runSingleUpload(
